class TestSkill:
    """Tests for the Skill dataclass."""

    def test_skill_creates_all_fields(self):
        data = {
            "id": "skill-1",
            "name": "my-skill",
            "description": "A test skill",
            "author": "tester",
            "stars": 42,
            "category": "productivity",
            "is_official": True,
        }
        skill = Skill(data)

        assert skill.id == "skill-1"
        assert skill.name == "my-skill"
        assert skill.description == "A test skill"
        assert skill.author == "tester"
        assert skill.stars == 42
        assert skill.category == "productivity"
        assert skill.is_official is True
        assert skill._data == data

    def test_skill_defaults_is_official_false(self):
        data = {
            "id": "skill-2",
            "name": "unofficial-skill",
            "description": "Not official",
            "author": "tester",
            "stars": 0,
            "category": "misc",
        }
        skill = Skill(data)

        assert skill.is_official is False

    def test_skill_repr(self):
        data = {
            "id": "skill-3",
            "name": "repr-skill",
            "description": "Repr test",
            "author": "alice",
            "stars": 10,
            "category": "test",
        }
        skill = Skill(data)

        assert "skill-3" in repr(skill)
        assert "repr-skill" in repr(skill)
        assert "alice" in repr(skill)


