class TestClawHubSyncListSkills:
    """Tests for ClawHub.list_skills (sync)."""

    def test_list_skills_returns_skill_objects(self):
        skills_data = [
            {
                "id": "s1",
                "name": "Skill One",
                "description": "First skill",
                "author": "alice",
                "stars": 5,
                "category": "ai",
            },
            {
                "id": "s2",
                "name": "Skill Two",
                "description": "Second skill",
                "author": "bob",
                "stars": 10,
                "category": "tools",
                "is_official": True,
            },
        ]

        mock_client = Mock(spec=httpx.Client)
        mock_client.get.return_value = make_response(200, skills_data)
        hub = ClawHub(mock_client)

        skills = hub.list_skills()

        assert len(skills) == 2
        assert all(isinstance(s, Skill) for s in skills)
        assert skills[0].name == "Skill One"
        assert skills[1].is_official is True
        mock_client.get.assert_called_once_with("/v1/clawhub/skills")

    def test_list_skills_raises_on_async_client(self):
        mock_client = Mock(spec=httpx.AsyncClient)
        hub = ClawHub(mock_client)

        with pytest.raises(RuntimeError, match="Use alist_skills"):
            hub.list_skills()

    def test_list_skills_raises_on_http_error(self):
        mock_client = Mock(spec=httpx.Client)
        mock_client.get.return_value = make_response(500, {"error": "server error"})
        hub = ClawHub(mock_client)

        with pytest.raises(httpx.HTTPStatusError):
            hub.list_skills()


