@pytest.mark.asyncio
class TestClawHubAsyncListSkills:
    """Tests for ClawHub.alist_skills (async)."""

    async def test_alist_skills_returns_skill_objects(self):
        skills_data = [
            {
                "id": "s1",
                "name": "Async Skill",
                "description": "An async skill",
                "author": "bob",
                "stars": 7,
                "category": "async_tools",
            },
        ]

        # httpx Response methods are synchronous; await is only on client.get()
        mock_response = Mock(spec=httpx.Response)
        mock_response.status_code = 200
        mock_response.json = Mock(return_value=skills_data)
        mock_response.raise_for_status = Mock()

        mock_client = AsyncMock(spec=httpx.AsyncClient)
        mock_client.get.return_value = mock_response
        hub = ClawHub(mock_client)

        skills = await hub.alist_skills()

        assert len(skills) == 1
        assert isinstance(skills[0], Skill)
        assert skills[0].name == "Async Skill"
        mock_client.get.assert_called_once_with("/v1/clawhub/skills")

    async def test_alist_skills_raises_on_sync_client(self):
        mock_client = Mock(spec=httpx.Client)
        hub = ClawHub(mock_client)

        with pytest.raises(RuntimeError, match="Use list_skills"):
            await hub.alist_skills()

    async def test_alist_skills_raises_on_http_error(self):
        # httpx Response.raise_for_status() is synchronous
        mock_response = Mock(spec=httpx.Response)
        mock_response.status_code = 500
        mock_response.json = Mock(return_value={"error": "server error"})
        mock_response.raise_for_status = Mock(
            side_effect=httpx.HTTPStatusError(
                "error", request=Mock(spec=httpx.Request), response=mock_response
            )
        )

        mock_client = AsyncMock(spec=httpx.AsyncClient)
        mock_client.get.return_value = mock_response
        hub = ClawHub(mock_client)

        with pytest.raises(httpx.HTTPStatusError):
            await hub.alist_skills()


